import { useState } from "react";

function StatCard({ title, value, color }) {
  return (
    <div
      style={{
        background: "#313244",
        padding: "20px",
        borderRadius: "8px",
        minWidth: "150px",
        borderTop: `4px solid `,
        borderTopColor: color,
      }}
    >
      <h3 style={{ margin: "0 0 10px 0", color: "#a6adc8", fontSize: "14px" }}>
        {title}
      </h3>
    </div>
  );
}
